class Solution:
    def getMaximumConsecutive(self, coins):
        coins = sorted(coins)
        reach = 0
        for c in coins:
            if c <= reach + 1:
                reach += c
            else:
                break
        return reach + 1

solutions.python:
class Solution:
    def getMaximumConsecutive(self, coins):
        coins.sort()
        ans = 1
        for c in coins:
            if c > ans:
                break
            ans += c
        return ans

